def _to_float(val):
    if val is None:
        return None
    if isinstance(val, (int, float)):
        return float(val)
    # Try to extract numeric value from string like "1.89 mIU/L"
    match = re.search(r'[-+]?\d*\.?\d+', str(val))
    return float(match.group()) if match else None

