def extract_numeric_value_and_date(observation):
    """
    Extract the numeric value and effective date from a FHIR Observation resource.
    Returns (value, date) tuple or None if value is missing.
    """
    # Extract the value
    value_quantity = observation.get('valueQuantity', {})
    if not value_quantity:
        return None

    value_str = value_quantity.get('value')
    if value_str is None:
        return None

    # Convert to float
    try:
        value = float(value_str)
    except (ValueError, TypeError):
        return None

    # Extract the effective date
    effective_date = observation.get('effectiveDateTime')
    if not effective_date:
        effective_period = observation.get('effectivePeriod', {})
        effective_date = effective_period.get('start')
    if not effective_date:
        meta = observation.get('meta', {})
        effective_date = meta.get('lastUpdated')

    return (value, effective_date)

